. Secured long-term contracts with Petronas, PRPC, PRefChem, Aramco, and Samsung etc.", "experiences/4/jobEndedOn": "9-2019", "experiences/4/jobLocation": "Johor, Malaysia", "experiences/4/jobStartedOn": "1-2018", "experiences/4/jobStillWorking": "false", "experiences/4/title": "Resort Manager (Cluster)", "experiences/5/companyId": "27165", "experiences/5/companyIndustry": "Hospitality", "experiences/5/companyLink1": "https://www.linkedin.com/company/the-ascott-limited/", "experiences/5/companyName": "The Ascott Limited", "experiences/5/companySize": "5001-10000", "experiences/5/companyUrn": "urn:li:fsd_company:27165", "experiences/5/companyWebsite": "https://www.discoverasr.com/en/the-ascott-limited", "experiences/5/employmentType": "Full-time", "experiences/5/jobDescription": "Led pre-opening and post-launch operations of a 4-star 310-unit serviced residence backed by Khazanah & Temasek. Delivered operational excellence and strong financial performance, reporting to both operator and owning board. Created performance dashboards, optimised RevPAR, and elevated guest satisfaction.", "experiences/5/jobEndedOn": "12-2017", "experiences/5/jobLocation": "Johor, Malaysia", "experiences/5/jobLocationCountry": "SG", "experiences/5/jobStartedOn": "12-2015", "experiences/5/jobStillWorking": "false", "experiences/5/logo": "https://media.licdn.com/dms/image/v2/C560BAQGFVLcDYiMtfA/company-logo_400_400/company-logo_400_400/0/1634719519029/the_ascott_limited_logo?e=1778112000&v=beta&t=NUzoWBbJHbC7BC1vPn8HdqOz8qLWS7VaiY9wtHcCuaA", "experiences/5/title": "Residence Manager (Pre-opening)", "experiences/6/companyName": "Avangio Hotel Kota Kinabalu Managed By Accor", "experiences/6/employmentType": "Contract", "experiences/6/jobDescription": "Short-term F&B turnaround project across 5 outlets and 2 kitchens. Focused on restructuring operations, reducing food cost, and improving kitchen workflow.", "experiences/6/jobEndedOn": "11-2015", "experiences/6/jobLocation": "Sabah, Malaysia", "